const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const phone = (j.phone === undefined || j.phone === null || j.phone === '') ? null : String(j.phone);
  const convIdRaw = j.chatwoot_conversation_id;
  const convId = (convIdRaw === undefined || convIdRaw === null || convIdRaw === '') ? null : parseInt(convIdRaw, 10);
  const inboxIdRaw = j.chatwoot_inbox_id;
  const inboxId = (inboxIdRaw === undefined || inboxIdRaw === null || inboxIdRaw === '') ? 1 : parseInt(inboxIdRaw, 10);
  const contactIdRaw = j.chatwoot_contact_id;
  const contactId = (contactIdRaw === undefined || contactIdRaw === null || contactIdRaw === '') ? null : parseInt(contactIdRaw, 10);
  const leadId = (j.lead_id === undefined || j.lead_id === null || j.lead_id === '') ? null : String(j.lead_id);
  const handoffReason = (j.handoff_reason === undefined || j.handoff_reason === null || j.handoff_reason === '') ? 'unspecified' : String(j.handoff_reason);
  const summary = (j.summary === undefined || j.summary === null) ? '' : String(j.summary);
  const callbackPeriod = (j.callback_period === undefined || j.callback_period === null || j.callback_period === '') ? null : String(j.callback_period);
  const ownerFlow = (j.owner_flow === undefined || j.owner_flow === null || j.owner_flow === '') ? 'after_hours' : String(j.owner_flow);
  const nome = (j.nome === undefined || j.nome === null || j.nome === '') ? null : String(j.nome);
  const testRunId = (j.test_run_id === undefined || j.test_run_id === null) ? null : String(j.test_run_id);
  const skipChatwoot = j._skip_chatwoot_calls === true;
  return {
    json: {
      phone,
      chatwoot_conversation_id: convId,
      chatwoot_inbox_id: inboxId,
      chatwoot_contact_id: contactId,
      lead_id: leadId,
      handoff_reason: handoffReason,
      summary,
      callback_period: callbackPeriod,
      owner_flow: ownerFlow,
      nome,
      test_run_id: testRunId,
      _skip_chatwoot_calls: skipChatwoot
    }
  };
});

const v = $('Validate Payload').first().json;
const payload = {
  handoff_reason: v.handoff_reason,
  owner_flow: v.owner_flow,
  summary: v.summary,
  callback_period: v.callback_period,
  lead_id: v.lead_id,
  chatwoot_conversation_id: v.chatwoot_conversation_id,
  nome: v.nome,
  test_run_id: v.test_run_id
};
return [{
  json: {
    chatwoot_conversation_id: v.chatwoot_conversation_id,
    handoff_payload_json: JSON.stringify(payload)
  }
}];

const v = $('Validate Payload').first().json;
const nome = v.nome || 'Obrigada';
const callback = v.callback_period || 'o quanto antes';
const text = `${nome}, perfeito. Já anotei tudo aqui e a equipe do Dr. Igor vai te chamar no período que você indicou (${callback}) para seguir o atendimento e ver os próximos passos. Até logo!`;
const dryPayload = {
  phone: v.phone,
  final_text: text,
  target: 'evolution_sendText',
  test_run_id: v.test_run_id
};
return [{
  json: {
    chatwoot_conversation_id: v.chatwoot_conversation_id,
    final_text: text,
    dry_payload_json: JSON.stringify(dryPayload),
    test_run_id: v.test_run_id
  }
}];
